interface ToolbarGroup {
  toolbars: Toolbar[];
  active: Toolbar | null;
  controls: [string, HTMLElement][];
  bound: WeakSet<HTMLElement>;
  observer: MutationObserver | null;
}

const groups = new WeakMap<HTMLElement, ToolbarGroup>();

function getGroup(container: HTMLElement): ToolbarGroup {
  let group = groups.get(container);
  if (group == null) {
    group = {
      toolbars: [],
      active: null,
      controls: [],
      bound: new WeakSet(),
      observer: null,
    };
    groups.set(container, group);
  }
  return group;
}

function isAttached(toolbar: Toolbar) {
  return document.body.contains(toolbar.quill.root);
}

// Drops toolbars whose editor is no longer in the document and clears a
// stale `active` reference so that shared controls do nothing until a
// remaining live editor becomes active again.
function pruneGroup(group: ToolbarGroup) {
  group.toolbars = group.toolbars.filter(isAttached);
  if (group.active != null && !isAttached(group.active)) {
    group.active = null;
  }
